#include <stdio.h>
#include <stdlib.h>

int lower_bound(long long *arr, int left, int right, long long target) {
    int lo = left, hi = right, ans = -1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (arr[mid] >= target) {
            ans = mid;
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return ans;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, Q; scanf("%d %d", &N, &Q);
        long long *pref = (long long*)malloc((N+1)*sizeof(long long));
        pref[0] = 0;
        for (int i = 1; i <= N; ++i) {
            long long val; scanf("%lld", &val);
            pref[i] = pref[i-1] + val;
        }
        for (int qi = 0; qi < Q; ++qi) {
            int i; long long x; scanf("%d %lld", &i, &x);
            long long target = pref[i-1] + x;
            int j = lower_bound(pref, i, N, target);
            if (j == -1) printf("-1"); else printf("%d", j);
            if (qi + 1 < Q) printf(" ");
        }
        if (T) printf("\n");
        free(pref);
    }
    return 0;
}

