import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int Q = fs.nextInt();
            long[] pref = new long[N + 1];
            for (int i = 1; i <= N; i++) {
                pref[i] = pref[i - 1] + fs.nextLong();
            }
            for (int q = 0; q < Q; q++) {
                int i = fs.nextInt();
                long x = fs.nextLong();
                long target = pref[i - 1] + x;
                int lo = i, hi = N, ans = -1;
                while (lo <= hi) {
                    int mid = lo + (hi - lo) / 2;
                    if (pref[mid] >= target) {
                        ans = mid;
                        hi = mid - 1;
                    } else {
                        lo = mid + 1;
                    }
                }
                out.append(ans == -1 ? -1 : ans);
                if (q + 1 < Q) out.append(' ');
            }
            if (T > 0) out.append('\n');
        }
        System.out.print(out.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

